For each order, evaluate insertions into all current and one potential new assign using a composite score combining marginal time efficiency, capacity utilization balance, and route compactness, selecting the insertion with highest score, falling back to a new empty assign if none exist or all fail.}
func InsertShips(dispatch Dispatch, oris, dess []Station, total_ship int) Dispatch {
	orderCount := len(oris)
	for jj := 0; jj < orderCount; jj++ {
		bestIdx := -1
		bestScore := -1e100
		orderId := total_ship + jj
		ori := oris[jj]
		des := dess[jj]
		tryLimit := dispatch.AssignsLen
		if tryLimit < MAXASSIGNS {
			tryLimit++
		}
		for ii := 0; ii < tryLimit; ii++ {
			if ii >= MAXASSIGNS {
				break
			}
			var tmpAssign Assign
			if ii < dispatch.AssignsLen {
				tmpAssign = dispatch.Assigns[ii]
			}
			oldCost := tmpAssign.Cost
			ok := tmpAssign.AddShip(orderId, ori, des)
			if !ok {
				if ii < dispatch.AssignsLen {
					dispatch.Assigns[ii].RemoveShip(orderId)
					dispatch.Assigns[ii].GenRoute()
				}
				continue
			}
			tmpAssign.GenRoute()
			newCost := tmpAssign.Cost
			if newCost < 0 {
				if ii < dispatch.AssignsLen {
					dispatch.Assigns[ii].RemoveShip(orderId)
					dispatch.Assigns[ii].GenRoute()
				}
				continue
			}
			delta := newCost - oldCost
			capacityUtil := 0.0
			loadSum := 0
			if ii < dispatch.AssignsLen {
				for _, s := range dispatch.Assigns[ii].Stations {
					loadSum += s.Load
				}
			}
			loadSum += ori.Load + des.Load
			maxCap := 10000
			if maxCap > 0 {
				capacityUtil = float64(loadSum) / float64(maxCap)
			}
			compactness := 0.0
			if len(tmpAssign.Stations) >= 2 {
				totalDist := 0.0
				for k := 0; k < len(tmpAssign.Stations)-1; k++ {
					totalDist += cal_dis(tmpAssign.Stations[k], tmpAssign.Stations[k+1])
				}
				if totalDist > 0 {
					meanX, meanY := 0.0, 0.0
					for _, s := range tmpAssign.Stations {
						meanX += float64(s.X)
						meanY += float64(s.Y)
					}
					meanX /= float64(len(tmpAssign.Stations))
					meanY /= float64(len(tmpAssign.Stations))
					spread := 0.0
					for _, s := range tmpAssign.Stations {
						dx := float64(s.X) - meanX
						dy := float64(s.Y) - meanY
						spread += dx*dx + dy*dy
					}
					compactness = 1.0 / (1.0 + spread/float64(len(tmpAssign.Stations)))
				}
			}
			score := -delta*0.7 + capacityUtil*300.0 + compactness*500.0
			if score > bestScore {
				bestScore = score
				bestIdx = ii
			}
			if ii < dispatch.AssignsLen {
				dispatch.Assigns[ii].RemoveShip(orderId)
				dispatch.Assigns[ii].GenRoute()
			}
		}
		finalIdx := bestIdx
		if finalIdx == -1 {
			finalIdx = dispatch.AssignsLen
			if finalIdx >= MAXASSIGNS {
				finalIdx = 0
				for fallbackIdx := 0; fallbackIdx < MAXASSIGNS; fallbackIdx++ {
					testAssign := dispatch.Assigns[fallbackIdx]
					if testAssign.AddShip(orderId, ori, des) {
						testAssign.GenRoute()
						if testAssign.Cost >= 0 {
							finalIdx = fallbackIdx
							break
						}
						testAssign.RemoveShip(orderId)
						testAssign.GenRoute()
					}
				}
			}
		}
		ok := dispatch.Assigns[finalIdx].AddShip(orderId, ori, des)
		if ok {
			dispatch.Assigns[finalIdx].GenRoute()
			if finalIdx >= dispatch.AssignsLen {
				dispatch.AssignsLen = finalIdx + 1
			}
		} else {
			dispatch.Assigns[finalIdx].RemoveShip(orderId)
			dispatch.Assigns[finalIdx].GenRoute()
		}
	}
	dispatch.RenewnTotalCost()
	return dispatch

